    long long* results = (long long*)malloc(q * sizeof(long long));
    for (int i = 0; i < q; i++) scanf("%d %d", &ls[i], &rs[i]);
    mo_algorithm_impl(n, arr, q, ls, rs, results);
    for (int i = 0; i < q; i++) {
        if (i) printf(" ");
