        Array.Sort(order, (a, b) =>
        {
            int ba = queries[a][0] / block, bb = queries[b][0] / block;
            if (ba != bb) return ba.CompareTo(bb);
            return ba % 2 == 0 ? queries[a][1].CompareTo(queries[b][1]) : queries[b][1].CompareTo(queries[a][1]);
